-- advance identity sequences past explicit-id seeds
SELECT setval(pg_get_serial_sequence('users','id'), (SELECT MAX(id) FROM users));
SELECT setval(pg_get_serial_sequence('topics','id'), (SELECT MAX(id) FROM topics));
SELECT setval(pg_get_serial_sequence('replies','id'), (SELECT MAX(id) FROM replies));
SELECT setval(pg_get_serial_sequence('blog_categories','id'), (SELECT MAX(id) FROM blog_categories));
SELECT setval(pg_get_serial_sequence('blog_tags','id'), (SELECT MAX(id) FROM blog_tags));
SELECT setval(pg_get_serial_sequence('blog_series','id'), (SELECT MAX(id) FROM blog_series));
